#include <bits/stdc++.h>
using namespace std;

const int N=1003;

struct Edge{
    int to,val;
};

int n,m,k,dist[N];
vector<Edge> g[N];

bool bfs(int len){
    memset(dist,0x3f,sizeof(dist));
    deque<int> q;
    q.push_back(1);
    dist[1]=0;
    while(q.size()){
        int x=q.front();
        q.pop_front();
        for(Edge y:g[x])
            if(dist[y.to]>dist[x]+(y.val>len)){
                dist[y.to]=dist[x]+(y.val>len);
                if(y.val>len)
                    q.push_back(y.to);
                else
                    q.push_front(y.to);
            }
    }
    return dist[n]<=k;
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    int l=0,r=0;
    for(int i=0,u,v,w;i<m;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
        r=max(r,w);
    }
    if(!bfs(r+1)){
        printf("-1");
        return 0;
    }
    while(l<r){
        int mid=l+r>>1;
        if(bfs(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
